import{_ as a,c as r,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Intégration z.ai : explication détaillée des limites de capacités | Antigravity-Manager","description":"Maîtrisez les limites de l'intégration z.ai d'Antigravity Tools. Comprenez le routage des demandes, la répartition dispatch_mode, le mappage des modèles, la stratégie de sécurité des en-têtes, ainsi que le proxy inverse et les limitations MCP, pour éviter les mauvaises interprétations.","frontmatter":{"title":"Intégration z.ai : explication détaillée des limites de capacités | Antigravity-Manager","sidebarTitle":"Référence rapide des limites z.ai","subtitle":"Intégration z.ai : explication détaillée des limites de capacités","description":"Maîtrisez les limites de l'intégration z.ai d'Antigravity Tools. Comprenez le routage des demandes, la répartition dispatch_mode, le mappage des modèles, la stratégie de sécurité des en-têtes, ainsi que le proxy inverse et les limitations MCP, pour éviter les mauvaises interprétations.","tags":["z.ai","MCP","Claude","Limites de capacités"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}`),o={name:"fr/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function s(n,e,l,d,c,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="limites-des-capacites-d-integration-z-ai-implemente-vs-explicitement-non-implemente" tabindex="-1">Limites des capacités d&#39;intégration z.ai (implémenté vs explicitement non implémenté) <a class="header-anchor" href="#limites-des-capacites-d-integration-z-ai-implemente-vs-explicitement-non-implemente" aria-label="Permalink to &quot;Limites des capacités d&#39;intégration z.ai (implémenté vs explicitement non implémenté)&quot;">​</a></h1><p>Ce document traite uniquement des « limites » de z.ai dans Antigravity Tools, et non de « comment se connecter ». Si vous constatez qu&#39;une certaine capacité ne fonctionne pas, venez d&#39;abord vérifier ici : est-ce qu&#39;elle n&#39;est pas activée, pas configurée, ou tout simplement pas implémentée.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-chapitre" tabindex="-1">Ce que vous pourrez faire après ce chapitre <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-chapitre" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce chapitre&quot;">​</a></h2><ul><li>Juger si vous devez compter sur z.ai : ce qui est « implémenté », ce qui est « explicitement non fait »</li><li>Comprendre quels points de terminaison sont affectés par z.ai (et lesquels ne le sont pas du tout)</li><li>Voir les preuves de code source/documentation pour chaque conclusion (avec liens vers les numéros de ligne GitHub), pour que vous puissiez vérifier par vous-même</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Vous avez peut-être déjà activé z.ai dans Antigravity Tools, mais dès que vous l&#39;utilisez, vous rencontrez ces doutes :</p><ul><li>Pourquoi certaines demandes passent par z.ai, d&#39;autres pas du tout ?</li><li>Les points de terminaison MCP peuvent-ils être considérés comme un « serveur MCP complet » ?</li><li>Les interrupteurs visibles dans l&#39;interface correspondent-ils réellement aux implémentations ?</li></ul><h2 id="qu-est-ce-que-l-integration-z-ai-dans-ce-projet" tabindex="-1">Qu&#39;est-ce que l&#39;intégration z.ai (dans ce projet) ? <a class="header-anchor" href="#qu-est-ce-que-l-integration-z-ai-dans-ce-projet" aria-label="Permalink to &quot;Qu&#39;est-ce que l&#39;intégration z.ai (dans ce projet) ?&quot;">​</a></h2><p><strong>L&#39;intégration z.ai</strong> dans Antigravity Tools est un « fournisseur amont + extension MCP » optionnel. Elle ne prend le contrôle des demandes de protocole Claude que dans des conditions spécifiques, et fournit un proxy inverse pour MCP Search/Reader et un serveur MCP Vision intégré minimaliste ; ce n&#39;est pas une solution de remplacement complet pour tous les protocoles et toutes les capacités.</p><div class="info custom-block"><p class="custom-block-title">À retenir en une phrase</p><p>Vous pouvez considérer z.ai comme un « fournisseur amont optionnel pour les demandes Claude + un ensemble de points de terminaison MCP activables », ne le considérez pas comme « importer toutes les capacités de z.ai ».</p></div><h2 id="implemente-stable-et-disponible-base-sur-le-code-source" tabindex="-1">Implémenté : stable et disponible (basé sur le code source) <a class="header-anchor" href="#implemente-stable-et-disponible-base-sur-le-code-source" aria-label="Permalink to &quot;Implémenté : stable et disponible (basé sur le code source)&quot;">​</a></h2><h3 id="_1-seul-le-protocole-claude-passe-par-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Seul le protocole Claude passe par z.ai (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-seul-le-protocole-claude-passe-par-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Seul le protocole Claude passe par z.ai (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>Le transfert du fournisseur amont Anthropic z.ai ne se produit que dans la branche z.ai du handler Claude :</p><ul><li><code>POST /v1/messages</code> : lorsque <code>use_zai=true</code>, appelle <code>forward_anthropic_json(...)</code> pour transférer la demande JSON vers le point de terminaison Anthropic compatible z.ai</li><li><code>POST /v1/messages/count_tokens</code> : lorsque z.ai est activé, transfère également ; sinon renvoie un espace réservé <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>Preuves :</p><ul><li>Sélection de la branche z.ai et point d&#39;entrée de transfert : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Branche z.ai et retour d&#39;espace réservé pour count_tokens : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Implémentation du transfert Anthropic z.ai : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">Comment comprendre « réponse en flux » ?</p><p><code>forward_anthropic_json</code> renvoie le corps de réponse du fournisseur amont en flux vers le client via <code>bytes_stream()</code>, sans analyser le SSE (voir construction du corps de réponse dans <code>providers/zai_anthropic.rs</code>).</p></div><h3 id="_2-«-signification-reelle-»-du-mode-de-repartition-dispatch-mode" tabindex="-1">2) « Signification réelle » du mode de répartition (dispatch_mode) <a class="header-anchor" href="#_2-«-signification-reelle-»-du-mode-de-repartition-dispatch-mode" aria-label="Permalink to &quot;2) « Signification réelle » du mode de répartition (dispatch_mode)&quot;">​</a></h3><p><code>dispatch_mode</code> détermine si <code>/v1/messages</code> passe par z.ai :</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>Ce qui se passe</th><th>Preuve</th></tr></thead><tbody><tr><td><code>off</code></td><td>N&#39;utilise jamais z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>Toutes les demandes Claude passent par z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Utilise z.ai uniquement lorsque le pool Google n&#39;est pas disponible (0 compte ou « aucun compte disponible »)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>Traite z.ai comme « 1 emplacement supplémentaire » participant à la rotation (ne garantit pas toujours d&#39;atteindre)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Malentendu courant sur pooled</p><p><code>pooled</code> n&#39;est pas « z.ai + pool de comptes Google tous utilisés, et répartition stable par poids ». Le code indique clairement « no strict guarantees », c&#39;est essentiellement un emplacement de rotation (seulement si <code>slot == 0</code> passe par z.ai).</p></div><h3 id="_3-mappage-des-modeles-comment-les-noms-de-modeles-claude-deviennent-ils-les-glm-de-z-ai" tabindex="-1">3) Mappage des modèles : comment les noms de modèles Claude deviennent-ils les glm-* de z.ai ? <a class="header-anchor" href="#_3-mappage-des-modeles-comment-les-noms-de-modeles-claude-deviennent-ils-les-glm-de-z-ai" aria-label="Permalink to &quot;3) Mappage des modèles : comment les noms de modèles Claude deviennent-ils les glm-* de z.ai ?&quot;">​</a></h3><p>Avant de transférer vers z.ai, si le corps de la demande contient un champ <code>model</code>, il sera réécrit :</p><ol><li>Correspondance exacte de <code>proxy.zai.model_mapping</code> (prend en charge à la fois la chaîne originale et la clé en minuscules)</li><li>Préfixe <code>zai:&lt;model&gt;</code> : supprime <code>zai:</code> et utilise directement</li><li><code>glm-*</code> : reste inchangé</li><li>Non <code>claude-*</code> : reste inchangé</li><li><code>claude-*</code> et contient <code>opus/haiku</code> : mappe vers <code>proxy.zai.models.opus/haiku</code> ; sinon par défaut <code>sonnet</code></li></ol><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-strategie-de-securite-des-en-tetes-lors-du-transfert-eviter-la-fuite-de-la-cle-proxy-locale" tabindex="-1">4) Stratégie de sécurité des en-têtes lors du transfert (éviter la fuite de la clé proxy locale) <a class="header-anchor" href="#_4-strategie-de-securite-des-en-tetes-lors-du-transfert-eviter-la-fuite-de-la-cle-proxy-locale" aria-label="Permalink to &quot;4) Stratégie de sécurité des en-têtes lors du transfert (éviter la fuite de la clé proxy locale)&quot;">​</a></h3><p>Le transfert du fournisseur amont z.ai ne « transfère pas tous les en-têtes tels quels », mais met en place deux lignes de défense :</p><ul><li>Ne laisse passer qu&#39;une petite partie des en-têtes (comme <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>Injecte la clé API z.ai dans le fournisseur amont (privilégie le mode d&#39;authentification utilisé par le client : <code>x-api-key</code> ou <code>Authorization: Bearer ...</code>)</li></ul><p>Preuves :</p><ul><li>Liste blanche des en-têtes : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>Injection de l&#39;authentification z.ai : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="implemente-mcp-proxy-inverse-search-reader-vision-integre" tabindex="-1">Implémenté : MCP (proxy inverse Search/Reader + Vision intégré) <a class="header-anchor" href="#implemente-mcp-proxy-inverse-search-reader-vision-integre" aria-label="Permalink to &quot;Implémenté : MCP (proxy inverse Search/Reader + Vision intégré)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-proxy-inverse-vers-les-points-de-terminaison-mcp-de-z-ai" tabindex="-1">1) MCP Search/Reader : proxy inverse vers les points de terminaison MCP de z.ai <a class="header-anchor" href="#_1-mcp-search-reader-proxy-inverse-vers-les-points-de-terminaison-mcp-de-z-ai" aria-label="Permalink to &quot;1) MCP Search/Reader : proxy inverse vers les points de terminaison MCP de z.ai&quot;">​</a></h3><p>Les points de terminaison locaux et l&#39;adresse amont sont codés en dur :</p><table tabindex="0"><thead><tr><th>Point de terminaison local</th><th>Adresse amont</th><th>Interrupteur</th><th>Preuve</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 n&#39;est pas un « problème réseau »</p><p>Tant que <code>proxy.zai.mcp.enabled=false</code>, ou que <code>web_search_enabled/web_reader_enabled=false</code> correspondant, ces points de terminaison renverront directement 404.</p></div><p>Preuves :</p><ul><li>Interrupteur général MCP et validation de la clé z.ai : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Enregistrement des routes : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-un-serveur-integre-«-mcp-http-streamable-minimaliste-»" tabindex="-1">2) Vision MCP : un serveur intégré « MCP HTTP Streamable minimaliste » <a class="header-anchor" href="#_2-vision-mcp-un-serveur-integre-«-mcp-http-streamable-minimaliste-»" aria-label="Permalink to &quot;2) Vision MCP : un serveur intégré « MCP HTTP Streamable minimaliste »&quot;">​</a></h3><p>Vision MCP n&#39;est pas un proxy inverse, c&#39;est une implémentation intégrée locale :</p><ul><li>Point de terminaison : <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> prend en charge : <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code> renvoie un keepalive SSE (nécessite une session initialisée)</li><li><code>DELETE</code> termine la session</li></ul><p>Preuves :</p><ul><li>Point d&#39;entrée principal du handler et répartition des méthodes : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Implémentation de <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code> : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Positionnement de « l&#39;implémentation minimale » de Vision MCP : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-ensemble-d-outils-vision-mcp-8-et-limites-de-taille-de-fichier" tabindex="-1">3) Ensemble d&#39;outils Vision MCP (8) et limites de taille de fichier <a class="header-anchor" href="#_3-ensemble-d-outils-vision-mcp-8-et-limites-de-taille-de-fichier" aria-label="Permalink to &quot;3) Ensemble d&#39;outils Vision MCP (8) et limites de taille de fichier&quot;">​</a></h3><p>La liste des outils provient de <code>tool_specs()</code> :</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>Les fichiers locaux sont lus et encodés en <code>data:&lt;mime&gt;;base64,...</code>, avec une limite stricte :</p><ul><li>Limite d&#39;image 5 Mo (<code>image_source_to_content(..., 5)</code>)</li><li>Limite vidéo 8 Mo (<code>video_source_to_content(..., 8)</code>)</li></ul><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="explicitement-non-implemente-a-ne-pas-attendre-base-sur-les-declarations-de-documentation-et-les-details-d-implementation" tabindex="-1">Explicitement non implémenté / à ne pas attendre (basé sur les déclarations de documentation et les détails d&#39;implémentation) <a class="header-anchor" href="#explicitement-non-implemente-a-ne-pas-attendre-base-sur-les-declarations-de-documentation-et-les-details-d-implementation" aria-label="Permalink to &quot;Explicitement non implémenté / à ne pas attendre (basé sur les déclarations de documentation et les détails d&#39;implémentation)&quot;">​</a></h2><h3 id="_1-surveillance-de-l-utilisation-budget-z-ai-usage-budget-non-implementee" tabindex="-1">1) Surveillance de l&#39;utilisation/budget z.ai (usage/budget) non implémentée <a class="header-anchor" href="#_1-surveillance-de-l-utilisation-budget-z-ai-usage-budget-non-implementee" aria-label="Permalink to &quot;1) Surveillance de l&#39;utilisation/budget z.ai (usage/budget) non implémentée&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> indique clairement « not implemented yet ». Cela signifie que :</p><ul><li>Vous ne pouvez pas compter sur Antigravity Tools pour fournir des requêtes ou des alertes d&#39;utilisation/budget z.ai</li><li>La gouvernance des quotas (Quota Protection) ne lira pas automatiquement les données de budget/utilisation de z.ai</li></ul><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-n-est-pas-un-serveur-mcp-complet" tabindex="-1">2) Vision MCP n&#39;est pas un serveur MCP complet <a class="header-anchor" href="#_2-vision-mcp-n-est-pas-un-serveur-mcp-complet" aria-label="Permalink to &quot;2) Vision MCP n&#39;est pas un serveur MCP complet&quot;">​</a></h3><p>Vision MCP est actuellement positionné comme une « implémentation minimale juste suffisante pour les appels d&#39;outils » : prompts/resources, la reprise (resumability), la sortie d&#39;outils en flux, etc. ne sont pas encore faits.</p><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-ne-reflete-pas-la-vraie-liste-de-modeles-z-ai" tabindex="-1">3) <code>/v1/models/claude</code> ne reflète pas la vraie liste de modèles z.ai <a class="header-anchor" href="#_3-v1-models-claude-ne-reflete-pas-la-vraie-liste-de-modeles-z-ai" aria-label="Permalink to &quot;3) `/v1/models/claude` ne reflète pas la vraie liste de modèles z.ai&quot;">​</a></h3><p>La liste des modèles renvoyée par ce point de terminaison provient du mappage intégré local et du mappage personnalisé (<code>get_all_dynamic_models</code>), elle n&#39;interroge pas le <code>/v1/models</code> du fournisseur amont z.ai.</p><p>Preuves :</p><ul><li>handler : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Logique de génération de liste : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="reference-rapide-des-champs-de-configuration-lies-a-z-ai" tabindex="-1">Référence rapide des champs de configuration (liés à z.ai) <a class="header-anchor" href="#reference-rapide-des-champs-de-configuration-lies-a-z-ai" aria-label="Permalink to &quot;Référence rapide des champs de configuration (liés à z.ai)&quot;">​</a></h2><p>La configuration z.ai se trouve sous <code>ProxyConfig.zai</code> et comprend ces champs :</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (remplacement par correspondance exacte)</li><li><code>models.{opus,sonnet,haiku}</code> (mappage par défaut de la famille Claude)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>Les valeurs par défaut (base_url / modèles par défaut) se trouvent également dans le même fichier :</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>Preuve : <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="resume-de-ce-chapitre" tabindex="-1">Résumé de ce chapitre <a class="header-anchor" href="#resume-de-ce-chapitre" aria-label="Permalink to &quot;Résumé de ce chapitre&quot;">​</a></h2><ul><li>z.ai ne prendra le contrôle que du protocole Claude (<code>/v1/messages</code> + <code>count_tokens</code>), les autres points de terminaison de protocole ne « passent pas automatiquement par z.ai »</li><li>MCP Search/Reader est un proxy inverse ; Vision MCP est une implémentation minimale locale, pas un serveur MCP complet</li><li>La liste des modèles de <code>/v1/models/claude</code> provient du mappage local et ne représente pas les vrais modèles du fournisseur amont z.ai</li></ul><hr><h2 id="apercu-du-prochain-chapitre" tabindex="-1">Aperçu du prochain chapitre <a class="header-anchor" href="#apercu-du-prochain-chapitre" aria-label="Permalink to &quot;Aperçu du prochain chapitre&quot;">​</a></h2><blockquote><p>Dans le prochain chapitre, nous étudierons <strong><a href="./../../changelog/release-notes/">Évolution des versions</a></strong>.</p></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Portée de l&#39;intégration z.ai (protocole Claude + MCP + Vision MCP)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>Mode de répartition z.ai et valeurs par défaut des modèles</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>base_url par défaut z.ai / modèles par défaut</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td>Logique de sélection si <code>/v1/messages</code> passe par z.ai</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td>Transfert z.ai et retour d&#39;espace réservé pour <code>/v1/messages/count_tokens</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>Transfert du fournisseur amont Anthropic z.ai (transfert JSON + réponse en flux)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>Règles de mappage des modèles z.ai (map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Proxy inverse MCP Search/Reader et interrupteurs</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Positionnement de l&#39;implémentation minimale Vision MCP (pas un serveur MCP complet)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Liste d&#39;outils Vision et limites (tool_specs + taille de fichier + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td>Source de la liste des modèles <code>/v1/models/claude</code> (mappage local, pas d&#39;interrogation amont)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>Surveillance de l&#39;utilisation/budget non implémentée (déclaration de documentation)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const h=a(o,[["render",s]]);export{m as __pageData,h as default};
